"""
MKT Christ Commentary — 2 Kings chapters 1–3
Run: python3 scripts/zc-christ-2kings-1-3.py

Ch1: Elijah identified by hairy garment/leather belt → John the Baptist (Matt 3:4; 11:14);
     fire from heaven / Luke 9:54 (disciples rebuked for wanting Elijah's fire);
     Baal-zebub → Beelzebul (Matt 12:24)
Ch2: Elijah's ascent in whirlwind → Acts 1:9 (Jesus' ascension);
     double portion of spirit → John 3:34 (Spirit without measure);
     fruitless body-search → Luke 24:5 (seek not the living among the dead);
     mantle transfer → John 14:12 (greater works through the Spirit)
Ch3: Spirit comes through worship / music → Acts 13:2;
     water without rain → John 7:37-39 (rivers of living water = Spirit);
     Mesha's firstborn sacrifice on wall → contrast with John 3:16 (God's Firstborn given freely)

Key typological connections:
- 1:8: hairy man, leather belt = Elijah marker → Matt 3:4 / Mark 1:6 (John the Baptist)
- 1:9-12: fire from heaven → Luke 9:54-55 (Jesus forbids the Elijah-fire move)
- 2:1: YHWH takes Elijah up in whirlwind → Acts 1:9 (divine passive ascension of Christ)
- 2:9: double-portion of spirit → John 3:34 (Spirit given without measure to the Son)
- 2:11: chariot of fire / ascent to heaven → Acts 1:9-11; Rev 19:11-14
- 2:13-14: mantle passed → Acts 2:33 (Spirit poured out from the ascended Christ)
- 2:16-18: search for Elijah's body fails → Luke 24:5-6 (he is not here; he is risen)
- 3:15: Spirit comes on Elisha through music → Acts 13:2 (Spirit speaks during worship)
- 3:16-17: water without rain → John 7:37-39 (Spirit as living water)
- 3:27: Mesha's firstborn sacrifice → contrast with John 3:16 (God's own Firstborn)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "1": {
    "1": "<p>Moab&rsquo;s rebellion after Ahab&rsquo;s death establishes the political crisis that frames Elijah&rsquo;s final ministry. The rebellion of a vassal people is simultaneously judgment — Ahab&rsquo;s dynasty has forfeited YHWH&rsquo;s protection. The withdrawal of divine blessing manifests in the loss of tribute; the pattern recurs at every level in the OT: covenant faithlessness produces the unraveling of order. What is inaugurated here is the final collapse of the house of Ahab, which Elijah had been commissioned to announce at Naboth&rsquo;s vineyard (1 Kgs 21:20-24). The Son who gathers all things under his Lordship (Col 1:17-18) is the antitype of every covenant claim that the kings of Israel could only partially enforce.</p>",
    "2": "<p>Ahaziah sends messengers to Baal-zebub (<em>baʿal zĕḇûḇ</em>, &lsquo;lord of flies&rsquo;) of Ekron to inquire whether he will recover. The name is almost certainly a scribal distortion of Baal-zebul (&lsquo;lord of the high place/mansion&rsquo;), and it is precisely as Beelzebul that the name appears in the NT. The Pharisees in Matt 12:24 accuse Jesus of casting out demons &lsquo;by Beelzebul, the prince of demons&rsquo; (<em>Beelzeboul archonti tōn daimoniōn</em>). Jesus&rsquo; reply (Matt 12:25-29) turns the accusation: if a kingdom is divided against itself it cannot stand; no one enters a strong man&rsquo;s house and plunders his goods without first binding the strong man. The lord of flies whom Ahaziah consults is the one Jesus binds (John 12:31 &lsquo;now the ruler of this world will be cast out&rsquo;). Ahaziah&rsquo;s flight to the demonic for health is the OT form of the refusal to seek life from the living God.</p>",
    "3": "<p>The angel of YHWH (<em>malʾaḵ YHWH</em>) commissions Elijah to intercept Ahaziah&rsquo;s messengers. Throughout Kings the angel of YHWH acts with full divine authority — sending, commissioning, touching, speaking words that are YHWH&rsquo;s own words. The angel of YHWH in the OT is not a created intermediary but the self-presentation of YHWH in communicative form, the pre-incarnate mode of divine engagement. The interrogative &lsquo;Is it because there is no God in Israel that you are going to inquire of Baal-zebub?&rsquo; (<em>hămibbĕlî ʾên-ʾĕlōhîm bĕyiśrāʾēl ʾattem hōlĕḵîm liḏrōš bĕbaʿal zĕḇûḇ</em>) is the diagnostic question of every idol-consultation in Israel&rsquo;s history — and the question implied in every act that bypasses Christ to seek life elsewhere (John 10:1 &lsquo;whoever does not enter by the door is a thief and robber&rsquo;).</p>",
    "4": "<p>The oracle: &lsquo;You shall not come down from that bed, for you shall surely die&rsquo; (<em>miṭṭāh ʾăšer-ʿālîtā šām lōʾ-tērēḏ mimmennāh kî môt tāmût</em>). The double infinitive absolute (<em>môt tāmût</em>) conveys certainty: the death is decreed. This is the inverse of Jesus&rsquo; healings, where the question is not &lsquo;will he live?&rsquo; but &lsquo;what will he do with his life?&rsquo; The prophet&rsquo;s word as death sentence stands in contrast to the word of the Son as life: John 5:24 &lsquo;whoever hears my word and believes him who sent me has eternal life&rsquo; (<em>echei zōēn aiōnion kai eis krisin ouk erchetai</em>). James 5:14-15 reverses the Ahaziah pattern: elders anointing the sick in the name of the Lord Jesus, the prayer of faith restoring the sick — seeking the living God through his appointed mediator produces life rather than death.</p>",
    "5": "<p>The messengers return early, without having reached Ekron. Ahaziah&rsquo;s question &lsquo;Why have you returned?&rsquo; begins the interrogation that will identify Elijah. The prophetic word has already accomplished its work before the king even hears it — it went out and intercepted its target (Isa 55:11 &lsquo;my word shall not return to me empty, but it shall accomplish that which I purpose&rsquo;).</p>",
    "6": "<p>The messengers repeat Elijah&rsquo;s oracle verbatim. The word of YHWH is transmitted without distortion — the messenger system works because the message is not the messengers&rsquo; own. John 12:49-50: &lsquo;For I have not spoken on my own authority, but the Father who sent me has himself given me a commandment — what to say and what to speak.&rsquo; The Son as the definitive messenger speaks the Father&rsquo;s words with the same fidelity.</p>",
    "7": "<p>Ahaziah asks: &lsquo;What kind of man was he?&rsquo; (<em>mah mišpāṭ hāʾîš ʾăšer ʿālāh liqrāʾtĕḵem wayyĕḏabbēr ʾălêḵem ʾet-haddĕḇārîm hāʾēlleh</em>). The identifying question focuses on external appearance as the marker of the prophet. The disciples also ask about appearances — and are regularly told that the inward reality overrides external expectation (Luke 7:25 &lsquo;What then did you go out to see?&rsquo;).</p>",
    "8": "<p>&lsquo;He was a hairy man (<em>baʿal śēʿār</em>), and wore a leather belt around his waist&rsquo; — and Ahaziah identifies him immediately: &lsquo;It is Elijah the Tishbite.&rsquo; This physical description becomes, in the NT, the identifying marker of Elijah&rsquo;s eschatological return. Matt 3:4: &lsquo;John wore a garment of camel&rsquo;s hair (<em>trichinas kamēlou</em>) and a leather belt around his waist (<em>zōnēn dermatinēn peri tēn osphyn autou</em>)&rsquo; — the description is nearly verbatim. Jesus identifies John explicitly as Elijah: Matt 11:14 &lsquo;if you are willing to accept it, he is Elijah who is to come&rsquo; (<em>autos estin Ēlias ho mellōn erchesthai</em>); Matt 17:12-13 &lsquo;Elijah has already come, and they did not recognize him&rsquo; — understood by the disciples as John the Baptist. The garment is not accidental detail; it is the sign of the prophetic office fulfilled.</p>",
    "9": "<p>The first captain of fifty comes to Elijah on his hill and demands: &lsquo;Man of God, the king says, &ldquo;Come down&rdquo;&rsquo; (<em>ʾîš hāʾĕlōhîm hammelek dibbēr rĕḏāh</em>). Elijah answers with fire from heaven: &lsquo;If I am a man of God, let fire come down from heaven and consume you and your fifty&rsquo; (<em>wĕtōḵal ʾōtĕḵā wĕʾet-ḥămišśîm</em>). Fire falls. The disciples James and John invoke this exact episode in Luke 9:54: &lsquo;Lord, do you want us to call fire down from heaven to consume them, as Elijah did?&rsquo; Jesus rebukes them (v55): &lsquo;You do not know what kind of spirit you are of; for the Son of Man did not come to destroy men&rsquo;s lives, but to save them.&rsquo; The Elijah-judgment-fire is not the spirit of Christ. The restraint of divine wrath and the extension of eschatological patience are specifically the mission of the Son (2 Pet 3:9 &lsquo;not wishing that any should perish, but that all should reach repentance&rsquo;).</p>",
    "10": "<p>Fire descends and consumes the captain and his fifty. The repeated fire-judgment on the first two companies demonstrates that the pattern is not accident — YHWH upholds his prophet and his word by direct intervention. The fire recalls Elijah&rsquo;s fire-contest at Carmel (1 Kgs 18:38) and anticipates the fire of Pentecost (Acts 2:3) — but where the Carmel fire consumed the sacrifice and the Pentecost fire rested on the disciples, the judgment-fire here consumes those who defy the prophetic word.</p>",
    "11": "<p>A second captain and his fifty repeat the demand verbatim. The doubling of the command and the doubling of the judgment seal the pattern. The scene is a controlled demonstration: those who approach YHWH&rsquo;s prophet under royal coercion rather than genuine inquiry receive the judgment their posture deserves.</p>",
    "12": "<p>Fire falls again on the second company. The repetition is designed to make the third encounter legible — the two fires establish the default; the mercy shown to the third captain is therefore the exception, not the rule, achieved by a different posture.</p>",
    "13": "<p>The third captain comes and falls on his knees before Elijah (<em>wayyiḵraʿ ʿal-birkāyw neḡed ʾēliyyāhû wayyiḥtannen ʾēlāyw wayyōʾmer ʾêlāyw ʾîš hāʾĕlōhîm tîqar-nāʾ napšî wĕnepeš ʿăḇāḏêḵā ʾēlleh bĕʿênêḵā</em>) — &lsquo;O man of God, please let my life and the life of these fifty servants of yours be precious in your eyes.&rsquo; The prostration and the plea for mercy succeed where the command failed. The posture of humility before the prophetic authority is the posture required before the one greater than the prophet. The petition &lsquo;let my life be precious in your eyes&rsquo; is the language of supplication before a sovereign — and it is met with mercy.</p>",
    "14": "<p>The captain acknowledges the fire that killed his two predecessors and appeals for mercy. The angel of YHWH immediately tells Elijah: &lsquo;Go down with him; do not be afraid of him.&rsquo; The divine authorization follows the human posture of humility. Heb 4:16: &lsquo;Let us therefore draw near to the throne of grace, that we may obtain mercy and find grace to help in time of need&rsquo; — the pattern of the third captain is the pattern of every approach to God through Christ.</p>",
    "15": "<p>&lsquo;Go down with him; do not be afraid.&rsquo; The angel of YHWH&rsquo;s reassurance to Elijah parallels the divine &lsquo;Do not fear&rsquo; throughout Scripture — the most common divine command. Elijah descends and delivers his oracle directly to Ahaziah, fulfilling his commission. The prophet who sits on his hill is also the prophet who goes wherever YHWH sends.</p>",
    "16": "<p>Elijah repeats the oracle directly to Ahaziah: &lsquo;Is it because there is no God in Israel to inquire of his word that you sent to inquire of Baal-zebub?&rsquo; (<em>haymibbĕlî ʾên-ʾĕlōhîm bĕyiśrāʾēl liḏrōš biḏḇārô</em>) — &lsquo;therefore you shall not come down from the bed to which you have gone up, for you shall surely die.&rsquo; The oracle is the same word repeated three times (vv4, 6, 16) — the word of YHWH does not change or soften with repetition. Heb 1:1-2: &lsquo;Long ago God spoke in many ways by the prophets; in these last days he has spoken by his Son&rsquo; — and what the Son speaks is final (John 12:48 &lsquo;the word I have spoken will be his judge on the last day&rsquo;).</p>",
    "17": "<p>Ahaziah dies &lsquo;according to the word of YHWH that Elijah had spoken&rsquo; (<em>kidiḇar YHWH ʾăšer dibber ʾēliyyāhû</em>). The prophetic fulfillment formula establishes that the prophetic word is identical in authority with the divine word — not the prophet&rsquo;s own but YHWH&rsquo;s own uttered through the prophet. Jehoram son of Jehoshaphat becomes king of Judah in the same year — the regnal synchronism preserving the unity of the narrative across both kingdoms.</p>",
    "18": "<p>The book of the chronicles of the kings of Israel contains &lsquo;the rest of the acts of Ahaziah&rsquo; — the regnal formula closes this brief, disastrous reign. Ahaziah sought health from Baal-zebub and received a death sentence from YHWH&rsquo;s prophet. The summing-up of his acts to a lost historical document underscores that the theological verdict is the permanent one; the rest is archival. The reader is invited to draw the contrast with the books that remain: the Psalms that celebrate seeking YHWH (Ps 34:4 &lsquo;I sought YHWH, and he answered me&rsquo;; Ps 27:8 &lsquo;seek my face&rsquo;) and the Son who is himself the goal of all seeking (Matt 7:7-8 &lsquo;seek and you will find&rsquo;).</p>"
  },
  "2": {
    "1": "<p>YHWH &lsquo;about to take up Elijah into heaven in a whirlwind&rsquo; (<em>behaʿălôt YHWH ʾet-ʾēliyyāhû baśśāʿārāh haššāmāyim</em>) — the Hiphil infinitive construct <em>haʿălôt</em> marks divine agency: YHWH is the actor who causes Elijah to go up. This is the third OT translation narrative: Enoch (&lsquo;God took him,&rsquo; Gen 5:24; Heb 11:5), Moses (whose grave is unknown, Deut 34:6 — early tradition understood this as a form of divine concealment), and Elijah. Acts 1:9 describes Jesus&rsquo; ascension with the same structure of divine initiative: <em>epērthē</em> (was lifted up, divine passive) and <em>nephelē hypelaben auton</em> (a cloud took him from their sight). The parallel is not incidental — Elijah&rsquo;s translation to heaven is the OT prototype for the ascension of Christ, with the crucial difference that Jesus first accomplished redemption before ascending to the right hand of the Father.</p>",
    "2": "<p>Elijah&rsquo;s instruction &lsquo;Stay here, for YHWH has sent me as far as Bethel&rsquo; (<em>šĕḇ-nāʾ pōh kî YHWH šĕlāḥanî ʿaḏ-bêt-ʾēl</em>) is met with Elisha&rsquo;s covenant oath: &lsquo;As YHWH lives and as you yourself live, I will not leave you&rsquo; (<em>ḥay-YHWH wĕḥê-napšĕḵā ʾim-ʾeʿezbĕkā</em>). The oath-formula is the language of Ruth 1:17 — covenantal loyalty that refuses separation regardless of cost. Elisha&rsquo;s refusal to leave Elijah mirrors the disciples&rsquo; following of Jesus: John 6:68 &lsquo;Lord, to whom shall we go? You have the words of eternal life.&rsquo; The journey from Gilgal toward the Jordan recapitulates Israel&rsquo;s founding geography in reverse, as if tracing the steps back to the originary crossing.</p>",
    "3": "<p>The sons of the prophets at Bethel confirm what they know: &lsquo;Do you know that today YHWH will take away your master from over you?&rsquo; (<em>hăyāḏaʿtā kî hayyôm YHWH lōqēaḥ ʾet-ʾăḏōnêḵā mēʿal rōʾšĕḵā</em>). Elisha says &lsquo;Yes, I know; keep quiet.&rsquo; The foreknowledge shared by the prophetic community recalls the disciples who knew that Jesus was going to the cross (Matt 16:21-22; John 13:1 &lsquo;Jesus knew that his hour had come to depart&rsquo;). The silence requested — &lsquo;keep quiet&rsquo; (<em>hăḏāšû</em>) — is not suppression of truth but the discipline of grief: some knowledge is held rather than spoken.</p>",
    "4": "<p>The pattern repeats at Jericho — Elijah says &lsquo;Stay here&rsquo;; Elisha refuses with the same oath. The three-part structure (Bethel, Jericho, Jordan) creates a procession to the sacred site of originary crossing. Jericho is the city of Joshua&rsquo;s first conquest — the place where the Jordan-crossing led to the first redemptive military victory. Elijah&rsquo;s final journey covers the sacred topography of Israel&rsquo;s entry into the land.</p>",
    "5": "<p>Sons of the prophets at Jericho repeat the same word about Elijah&rsquo;s imminent departure; Elisha answers identically. The prophetic community&rsquo;s foreknowledge creates a chorus of witnesses — the departure is not hidden but publicly anticipated. Acts 1:10-11 similarly involves two men (angels) in white robes who interpret the ascension to the astonished disciples: &lsquo;Men of Galilee, why do you stand looking into heaven? This Jesus, who was taken up from you into heaven, will come in the same way as you saw him go into heaven.&rsquo;</p>",
    "6": "<p>Third command to stay; third refusal with the covenant oath. The triple structure creates the narrative equivalent of a solemn ritual — Elisha&rsquo;s fidelity is tested and confirmed three times before the departure. The fifty sons of the prophets stand at a distance to watch. The community witness creates public accountability for what is about to happen; the translation of Elijah will not be a secret or disputed event within the prophetic community.</p>",
    "7": "<p>Fifty sons of the prophets stand opposite them at a distance (<em>waḥămiššîm ʾanšê bĕnê hanněḇîʾîm hālĕḵû wayyaʿamḏû minneḡeḏ mērāḥôq</em>). The number fifty recurs throughout the Elijah-Elisha cycle (the captains of ch1, the searchers in vv16-17); the prophetic community is a specific, numbered body. The distance they maintain is both practical (making space for what is about to happen) and theological — one does not approach the divine chariot carelessly. Rev 4:11 and the heavenly liturgy envisage a similar structure: concentric circles of worshipers around the divine throne, each at its appropriate distance.</p>",
    "8": "<p>Elijah takes his mantle (<em>ʾaddartô</em>), rolls it, and strikes the water; the waters divide (<em>wayyēḥāṣĕḇû hēnnāh wāhēnnāh</em>) and the two cross on dry ground. The third parting of the Jordan — after Joshua&rsquo;s entry (Josh 3-4) and this moment — establishes the pattern: the Jordan-crossing is always a commissioning event. Moses crossed the Red Sea to constitute Israel; Joshua crossed the Jordan to inherit the land; Elijah crosses to be taken to heaven; Elisha recrosses to inherit the ministry. The Jordan-crossing is, in each case, the moment of divine appointment. John the Baptist baptizes at the Jordan — and Jesus comes to be baptized there, after which the Spirit descends and the Father speaks (Matt 3:13-17): the Jordan becomes the site of the final, definitive commissioning of the one who fulfills all that the Jordan-crossings prefigure.</p>",
    "9": "<p>&lsquo;Ask what I shall do for you before I am taken from you.&rsquo; Elisha&rsquo;s request: &lsquo;Let a double portion of your spirit be on me&rsquo; (<em>yĕhî-nāʾ pî-šnayim bĕrûḥăḵā ʾēlay</em>). The phrase <em>pî-šnayim</em> (lit. &lsquo;mouth of two&rsquo;) is the inheritance term of Deut 21:17: the firstborn receives double the share of any other heir. Elisha is asking to be constituted as Elijah&rsquo;s spiritual firstborn, the primary heir of the prophetic gift. John 3:34 points to the fulfillment: &lsquo;For he whom God has sent utters the words of God, for he gives the Spirit not by measure (<em>ou gar ek metrou didōsin to pneuma</em>).&rsquo; The Son does not receive a &lsquo;double portion&rsquo; — he receives the Spirit without any measure at all; the Elisha-type is infinitely exceeded in the antitype.</p>",
    "10": "<p>&lsquo;You have asked a hard thing (<em>hiqšîtā lišʾôl</em>). If you see me taken from you, it shall be so for you; but if you do not see it, it shall not be so.&rsquo; Sight of the departure is the condition of reception — the disciple who witnesses the translation receives the guarantee of the spirit. Acts 1:8-9 employs the same structure: the disciples are gathered as witnesses of the ascension, and it is precisely because they see him taken up that they can receive what he sends from the Father. The vision of the departing Christ is not a consolation prize but a constitutive act: to see him go is to receive the promise of the Spirit.</p>",
    "11": "<p>&lsquo;A chariot of fire and horses of fire separated the two of them, and Elijah went up in the whirlwind to heaven&rsquo; (<em>reḵeḇ-ʾēš wĕsûsê ʾēš wayyaḇdilû bên šĕnêhem wayyaʿal ʾēliyyāhû baśśāʿārāh haššāmāyim</em>). The chariot of fire is the divine war-chariot (<em>merkāḇāh</em>) made momentarily visible, the vehicle of YHWH&rsquo;s glory. Acts 1:9: &lsquo;as they were looking on, he was lifted up (<em>epērthē</em>), and a cloud (<em>nephelē</em>) took him out of their sight&rsquo; — the cloud is the same divine presence that filled the tabernacle (Exod 40:34), led Israel in the wilderness (Exod 13:21), and filled the temple (1 Kgs 8:10-11). Rev 19:11-14 presents the returning Christ on a white horse with the armies of heaven — the eschatological actualization of what the chariot of fire briefly revealed. Elijah&rsquo;s ascent is the OT prototype of the ascension: both involve divine initiative, visible transport, and the watching community left behind with a commission.</p>",
    "12": "<p>Elisha&rsquo;s cry: &lsquo;My father, my father! The chariots of Israel and its horsemen!&rsquo; (<em>ʾāḇî ʾāḇî reḵeḇ yiśrāʾēl ûpārāšāyw</em>) — then silence; Elijah is gone, and he tears his garments in two. This same cry is repeated at Elisha&rsquo;s own deathbed (2 Kgs 13:14) — the prophets are identified as the true military strength of Israel, the divine protection that makes armies irrelevant. The grief of Elisha at Elijah&rsquo;s departure echoes the grief of the disciples before Jesus&rsquo; departure. John 16:6: &lsquo;Because I have said these things to you, sorrow has filled your heart.&rsquo; Jesus&rsquo; answer in John 16:7 is structurally identical to what happens in 2 Kgs 2: &lsquo;It is to your advantage that I go away, for if I do not go away, the Helper will not come to you.&rsquo; Elijah must depart so Elisha can receive the spirit; Jesus must ascend so the Paraclete can be sent.</p>",
    "13": "<p>Elisha picks up Elijah&rsquo;s mantle that has fallen. The mantle (<em>ʾadderet</em>) is the prophetic insignia — Elijah was identified by it (1 Kgs 19:19), and now it falls from him at the translation. To take up the mantle is to accept the prophetic succession, the responsibility for the ongoing prophetic mission. Jesus&rsquo; commission to the disciples (Matt 28:18-20) is the NT form of the mantle-passing: &lsquo;All authority in heaven and on earth has been given to me — therefore go.&rsquo; The disciples receive not a garment but the Spirit himself (Acts 1:8 &lsquo;you will receive power when the Holy Spirit comes upon you&rsquo;).</p>",
    "14": "<p>Elisha returns to the Jordan, strikes the water with Elijah&rsquo;s mantle, and says: &lsquo;Where is YHWH the God of Elijah?&rsquo; (<em>ʾayyēh YHWH ʾĕlōhê ʾēliyyāhû</em>) — the waters divide. The question is a prayer of appeal and an expression of faith: YHWH who worked through Elijah must still work; the God of the departed prophet is not absent with the prophet. Acts 2:33: the ascended Christ &lsquo;having received from the Father the promise of the Holy Spirit, has poured out this that you yourselves are seeing and hearing&rsquo; — the God of Jesus is not less present after the ascension but more so, in the Spirit poured out. Elisha&rsquo;s miracle confirms the succession; Pentecost confirms the commission.</p>",
    "15": "<p>&lsquo;The spirit of Elijah rests on Elisha&rsquo; (<em>nāḥāh rûaḥ ʾēliyyāhû ʿal-ʾĕlîšāʿ</em>) — the sons of the prophets see it and prostrate themselves. The transfer of prophetic spirit is visible to the community through the confirming sign. John 20:22: Jesus &lsquo;breathed on them and said, &ldquo;Receive the Holy Spirit.&rdquo;&rsquo; — the Spirit-transfer at the resurrection-appearance, like Elisha&rsquo;s inheritance at the Jordan, is witnessed and confirmed. The Spirit that rested on Elisha was a &lsquo;portion&rsquo; of Elijah&rsquo;s spirit; the Spirit given by the Son is the Spirit of God himself, given without measure.</p>",
    "16": "<p>The sons of the prophets propose sending fifty strong men to search for Elijah&rsquo;s body — &lsquo;Perhaps the Spirit of YHWH has lifted him and cast him on some mountain or into some valley.&rsquo; Elisha says &lsquo;Do not send.&rsquo; They press him; he yields. The refusal is theologically significant: Elisha knows the translation is genuine — Elijah has been taken to heaven, not relocated to a mountain. The proposal to search for a body that has been taken to heaven is the exact error that Luke 24:5 addresses: &lsquo;Why do you seek the living among the dead?&rsquo;</p>",
    "17": "<p>They send fifty men for three days and do not find Elijah (<em>lōʾ mĕṣāʾuhû</em>). Elisha says: &lsquo;Did I not say to you, &ldquo;Do not go&rdquo;?&rsquo; The fruitless three-day search for the translated prophet&rsquo;s body directly prefigures the empty tomb. Luke 24:1-6: the women arrive at the tomb on the third day, find the stone rolled away and the body not there (<em>to sōma tou kyriou Iēsou</em>), and are told by two men in dazzling apparel: &lsquo;Why do you seek the living among the dead? He is not here, but has risen.&rsquo; The structural parallel is exact: a genuine bodily departure to heaven leaves behind a community conducting a body-search that finds nothing, because the body is not there.</p>",
    "18": "<p>Elisha&rsquo;s response to the unsuccessful searchers: &lsquo;Did I not tell you not to go?&rsquo; The prophet who received the spirit knows what happened; those who did not witness the departure can only search futilely. The disciples who witnessed the resurrection appearances are the analogous community — Paul in 1 Cor 15:1-8 lists them as the ground of the resurrection proclamation. The fruitless search has its christological resolution in the empty tomb that confirms rather than contradicts the departure.</p>",
    "19": "<p>The men of Jericho report to Elisha that the water is bad (<em>rāʿîm</em>) and the land is causing miscarriage (<em>hāʾāreṣ mĕšakkulet</em>). The city of Joshua&rsquo;s first victory is afflicted with water that sustains no life. The curse on creation (Gen 3:17-19 &lsquo;cursed is the ground because of you&rsquo;) manifests in unfruitful earth and dangerous water; the land mirrors the spiritual condition of those who work it.</p>",
    "20": "<p>Elisha asks for a new bowl (<em>sĕpel ḥăḏāšāh</em>) with salt in it. &lsquo;New&rsquo; signals that the instrument must be uncontaminated; the salt is the purifying agent. He goes to the spring of the waters — the source, not the symptom. The healing must be at the origin, not the downstream effects. Jesus similarly goes to the root of spiritual disease — not the symptoms of sin (external acts) but the source (the heart, Matt 15:18-19). The new bowl anticipates the &lsquo;new covenant&rsquo; (<em>kainē diathēkē</em>) in which Jesus is the new vessel of the Spirit&rsquo;s healing work.</p>",
    "21": "<p>Elisha throws salt into the spring and declares: &lsquo;Thus says YHWH: I have healed these waters (<em>rippîtî lamayim hāʾēlleh</em>); death shall no longer come from them, nor shall they cause miscarriage.&rsquo; The formula &lsquo;Thus says YHWH&rsquo; (<em>kōh ʾāmar YHWH</em>) marks the healing as divine speech-act rather than magical technique; the salt is the sign, not the mechanism. Rev 22:1-2: &lsquo;the river of the water of life, bright as crystal, flowing from the throne of God and of the Lamb&rsquo; — the eschatological healing of all waters is the antitype of the Jericho spring. The Spirit is the water that heals at the source (John 4:14 &lsquo;the water I will give him will become in him a spring of water welling up to eternal life&rsquo;).</p>",
    "22": "<p>&lsquo;And the waters have been healed to this day&rsquo; (<em>wayyērāpĕʾû hammayim ʿaḏ hayyôm hazzeh kidiḇar ʾĕlîšāʿ ʾăšer dibber</em>) — the prophetic word effects a permanent change; the spring is healed, not merely temporarily improved. The healing is ongoing: the sign is durable. Matt 5:13: &lsquo;you are the salt of the earth&rsquo; — Jesus identifies his disciples as the purifying, healing presence in a world whose springs are bad. The salt in the new bowl carried by the disciples of Christ is the Spirit himself.</p>",
    "23": "<p>Elisha goes up to Bethel. On the way, young men (<em>nĕʿārîm qĕṭannîm</em>) come out of the city and mock him: &lsquo;Go up, baldy! Go up, baldy!&rsquo; (<em>ʿălēh qērēaḥ ʿălēh qērēaḥ</em>). The verb <em>ʿālāh</em> (go up) is the same root used of Elijah&rsquo;s ascent (vv1, 11) and of YHWH&rsquo;s taking Elijah up — the mocking &lsquo;go up&rsquo; is contempt for the prophetic office that Elisha has just inherited, directed at the successor of the translated prophet. The mockery of the prophet is the mockery of the prophetic word and, behind it, of YHWH who sent the prophet.</p>",
    "24": "<p>Elisha turns and curses them in the name of YHWH (<em>wayyiqallĕlēm bĕšēm YHWH</em>), and two she-bears come out of the woods and maul forty-two of the youths. The number forty-two reappears in Rev 13:5 as the duration of the beast&rsquo;s blasphemy — a period of unchecked mockery of God, after which judgment falls. The incident is severe; it does not yield to domestication. The christological reading is not typological comfort but warning: John 5:23 &lsquo;whoever does not honor the Son does not honor the Father who sent him&rsquo;; Matt 12:36-37 &lsquo;I tell you, on the day of judgment people will give account for every careless word they speak&rsquo;. The mocking of those who bear YHWH&rsquo;s prophetic name is an act of divine dishonor, and divine honor defends its servants.</p>",
    "25": "<p>Elisha goes on to Carmel, then returns to Samaria. The geography traces the prophetic mission: from the site of Elijah&rsquo;s great victory (1 Kgs 18) back to the capital of the northern kingdom. Elisha enters his ministry where Elijah&rsquo;s ended, in the places of confrontation with Baal-worship. The prophetic succession is not a fresh start but a continuous mission against the same idolatry in the same places. Jesus sends his disciples not to new territories but back to Jerusalem (Acts 1:8 &lsquo;beginning from Jerusalem&rsquo;) — the place of crucifixion is the first place of resurrection proclamation.</p>"
  },
  "3": {
    "1": "<p>Jehoram son of Ahab becomes king of Israel in Jehoshaphat&rsquo;s eighteenth year. The regnal synchronism marks the intersection of the two royal lines whose stories now converge for the Moab campaign. Jehoram&rsquo;s reign is theologically positioned: he removes the pillar of Baal (v2) but holds to the sin of Jeroboam — partial reform, halting faithfulness. The NT analog is the Laodicean condition (Rev 3:15-16): &lsquo;I know your works: you are neither cold nor hot. Would that you were either cold or hot! So, because you are lukewarm, and neither hot nor cold, I will spit you out of my mouth.&rsquo;</p>",
    "2": "<p>Jehoram removes the pillar of Baal (<em>wayyāsar ʾet-maṣṣeḇat habbaʿal ʾăšer ʿāśāh ʾāḇîw</em>) — specifically the Baal installation Ahab had made (1 Kgs 16:32-33). The partial reform acknowledges that the previous generation&rsquo;s apostasy was wrong, without fully returning to YHWH. This is the structural problem of every reform that removes the most visible offenses while leaving the systemic idolatry intact. Jesus&rsquo; parable of the house swept clean of one demon but subsequently occupied by seven (Matt 12:43-45) captures the dynamic: partial cleansing without the positive occupation of the Spirit produces a worse final state.</p>",
    "3": "<p>Jehoram holds to the sin of Jeroboam son of Nebat (<em>raq bĕḥaṭṭōʾt yārāḇĕʿām ben-nĕḇāṭ ʾăšer heḥĕṭîʾ ʾet-yiśrāʾēl dāḇaq lōʾ-sār mimmennāh</em>). The Jeroboam-formula is the standard theological assessment of all northern kings (1 Kgs 12:28-33 — the golden calves at Dan and Bethel, the unauthorized priesthood, the unlawful calendar). It functions as a recurring theological verdict: the structural sin that shaped the northern kingdom was never renounced. The &lsquo;sin of Jeroboam&rsquo; is unauthorized worship, the attempt to keep the covenant&rsquo;s benefits while replacing its appointed means. Heb 10:26: &lsquo;if we go on sinning deliberately after receiving the knowledge of the truth, there no longer remains a sacrifice for sins.&rsquo;</p>",
    "4": "<p>Mesha king of Moab was a sheep-breeder who paid tribute: 100,000 lambs and 100,000 rams with their wool. The Mesha Stele (Moabite Stone, c. 840 BCE, discovered 1868) is one of the most significant epigraphic finds in biblical archaeology: it corroborates the broad narrative of 2 Kings 3, names Omri of Israel, and contains the phrase <em>byt dwd</em> (house of David) — extra-biblical evidence for the Davidic dynasty within a generation of David&rsquo;s successors. The stele&rsquo;s existence confirms the historicity of the names and relationships in the Kings narrative; the biblical text is not isolated tradition.</p>",
    "5": "<p>When Ahab dies, Mesha rebels against the king of Israel. The withdrawal of tribute is a declaration of political independence. Every imperial system in the ancient Near East understood tribute as the material expression of submission; its withholding was a formal act of defiance. The coalition&rsquo;s campaign to restore tribute reflects the geopolitical reality of the period — but the text&rsquo;s theological interest is not in the tribute itself but in whether the campaign will be conducted with or without YHWH&rsquo;s guidance.</p>",
    "6": "<p>Jehoram musters Israel at Samaria and prepares for the Moab campaign, numbering all Israel. The mobilization of the full military strength for a campaign that will end in ambiguous withdrawal demonstrates that military capability is not the determinative factor. The narrative will make the outcome depend entirely on the word of the prophet, not on troop strength.</p>",
    "7": "<p>Jehoram invites Jehoshaphat of Judah to join the campaign: &lsquo;Will you go with me to battle against Moab?&rsquo; Jehoshaphat responds: &lsquo;I will go; I am as you are, my people as your people, my horses as your horses&rsquo; (<em>ʾēlēḵ kāmōnî kāmmôḵā kĕʿammî kĕʿammĕḵā kĕsûsay kĕsûsêḵā</em>) — a covenant-solidarity formula identical to the one Ahab extracted from him in 1 Kgs 22:4. Jehoshaphat&rsquo;s loyalty to the northern kingdom despite his own faithfulness to YHWH creates the theological tension that makes Elisha&rsquo;s participation meaningful: he comes because of Jehoshaphat, not because of Jehoram.</p>",
    "8": "<p>The coalition decides on the route through the wilderness of Edom (<em>derek midbar ʾeḏôm</em>). The king of Edom joins them — this three-kingdom alliance (Israel, Judah, Edom) is the human coalition that YHWH will use, despite Jehoram&rsquo;s unfaithfulness, because of Jehoshaphat&rsquo;s faithfulness and intercession. The route through Edom means a seven-day march around the southern end of the Dead Sea, adding the logistical strain that produces the water crisis of v9.</p>",
    "9": "<p>After seven days, there is no water for the army or animals. The water crisis in the wilderness recapitulates the Sinai pattern: Israel in the wilderness without water, dependent entirely on divine provision (Exod 17:1-7; Num 20:1-13; Ps 78:15-16). The crisis is the moment at which the campaign&rsquo;s dependence on YHWH becomes undeniable — human logistics have failed; only the divine word can supply what is needed.</p>",
    "10": "<p>Jehoram&rsquo;s response is despair: &lsquo;Alas! YHWH has called these three kings together to deliver them into the hand of Moab&rsquo; (<em>ʾăhāh kî-qārāʾ YHWH lišlōšet hammĕlāḵîm hāʾēlleh lātet ʾôtām bĕyaḏ-mwʾāḇ</em>). His interpretation reverses the truth — he assumes divine abandonment where YHWH is actually engineering the dependence that will make the prophetic word decisive. Despair in crisis is the recurring failure of the unfaithful king who knows enough about YHWH to blame him but not enough to seek him.</p>",
    "11": "<p>Jehoshaphat asks: &lsquo;Is there no prophet of YHWH here, that we may inquire of YHWH through him?&rsquo; (<em>hăyēš pōh nāḇîʾ lYHWH wĕniḏrĕšāh ʾet-YHWH mēʾittô</em>). A servant of the king of Israel identifies Elisha: &lsquo;who poured water on the hands of Elijah&rsquo; — the humble service role (washing the prophet&rsquo;s hands) is the identifying credential. Jehoshaphat: &lsquo;The word of YHWH is with him.&rsquo; The faithful king recognizes prophetic authority; the unfaithful king does not seek it. The NT pattern: the disciples who recognize Jesus as the one with &lsquo;the words of eternal life&rsquo; (John 6:68) are those whose hearts have already been prepared by faithfulness.</p>",
    "12": "<p>The three kings go down to Elisha. Elisha&rsquo;s rebuke of Jehoram is unambiguous: &lsquo;What do I have to do with you? Go to the prophets of your father and the prophets of your mother.&rsquo; Jehoram appeals: &lsquo;No; it is YHWH who has called these three kings together to give them into the hand of Moab.&rsquo; Elisha&rsquo;s counter: &lsquo;As YHWH of hosts lives, before whom I stand, were it not that I have regard for Jehoshaphat king of Judah, I would not look at you or see you.&rsquo; The prophetic access to YHWH is mediated through the righteous man — Jehoshaphat&rsquo;s presence is the intercessory ground on which YHWH&rsquo;s word comes. This is the typological pattern of intercession: Abraham for Sodom (Gen 18), Moses for Israel (Exod 32:10-14), and ultimately Christ for sinners (Rom 8:34 &lsquo;who is to condemn? Christ Jesus is the one who died — more than that, who was raised — who is at the right hand of God, who indeed is interceding for us&rsquo;).</p>",
    "13": "<p>Elisha&rsquo;s refusal to look at Jehoram — &lsquo;I would not look at you or see you&rsquo; (<em>lûlê pĕnê yĕhôšāpāṭ melek-yĕhûḏāh ʾănî nōśēʾ ʾim-ʾabbîṭ ʾēlêḵā wĕʾim-ʾerʾekā</em>) — establishes the moral condition of access. The prophet does not serve the unfaithful king on demand; the divine word is not available to those who have forfeited their claim to it. This is not petulance but prophetic clarity about the ground of covenant communication. Ps 66:18: &lsquo;If I had cherished iniquity in my heart, the Lord would not have listened.&rsquo;</p>",
    "14": "<p>Elisha asks for a harpist (<em>wĕʿattāh qĕḥû-lî mĕnaggēn</em>). The request for music before receiving the prophetic word links the Spirit&rsquo;s movement to the worshiping state — not as a technique or manipulation, but as the natural context of prophetic receptivity. 1 Sam 10:5-6: prophets descend from the high place playing harp, tambourine, flute, and lyre, and the Spirit of God rushes upon Saul. 1 Sam 16:23: David&rsquo;s harp playing quiets the evil spirit tormenting Saul. Ps 22:3: &lsquo;you are holy, enthroned on the praises of Israel&rsquo; — the divine presence inhabits praise. Acts 13:2: &lsquo;while they were worshiping the Lord and fasting, the Holy Spirit said...&rsquo; — the Spirit speaks in the context of ordered worship.</p>",
    "15": "<p>&lsquo;And when the minstrel played, the hand of YHWH came upon him&rsquo; (<em>wĕhāyāh kĕnaggēn hamĕnaggēn wayhî ʿālāyw yaḏ-YHWH</em>). The &lsquo;hand of YHWH&rsquo; (<em>yaḏ-YHWH</em>) is the standard formulation for prophetic inspiration in Ezekiel (1:3; 3:14, 22; 8:1; 37:1 etc.) and here in Kings — the overwhelming, compulsive movement of divine power through the prophet. The Spirit comes when and as YHWH wills (John 3:8 &lsquo;the wind blows where it wishes&rsquo;) but finds the prepared instrument. The worshiping prophet is the prepared vessel; the Spirit&rsquo;s coming is not earned but received.</p>",
    "16": "<p>Elisha declares: &lsquo;Thus says YHWH: Make this valley full of pools (<em>ʿāśôh hannāḥal hazzeh gēḇîm gēḇîm</em>)&rsquo; — dig ditches in the dry valley before any water arrives. The command to prepare for water without visible source is the prophetic pattern of faith: Noah building an ark before rain (Heb 11:7), Abraham going to a land he had not yet received (Heb 11:8). The advance preparation for the water of God&rsquo;s provision is the pattern Jesus enjoins: John 7:37-38 &lsquo;if anyone thirsts, let him come to me and drink... whoever believes in me, as the Scripture has said, &ldquo;Out of his heart will flow rivers of living water.&rdquo;&rsquo;</p>",
    "17": "<p>&lsquo;For thus says YHWH: You shall not see wind or rain, yet that valley shall be filled with water&rsquo; (<em>kî-ḵōh ʾāmar YHWH lōʾ-tirʾû rûaḥ wĕlōʾ-tirʾû māṭār wĕhannāḥal hahûʾ yimmālēʾ māyim</em>). The water comes by no visible mechanism — no storm front, no natural explanation. John 3:8: &lsquo;the wind blows where it wishes, and you hear its sound, but you do not know where it comes from or where it goes. So it is with everyone who is born of the Spirit.&rsquo; The Spirit&rsquo;s work, like this water, arrives from an invisible source through an unintelligible route, filling the prepared vessels.</p>",
    "18": "<p>&lsquo;This is a light thing in the eyes of YHWH (<em>wĕnāqēl zōʾt bĕʿênê YHWH</em>); he will also give Moab into your hand.&rsquo; The water miracle is a &lsquo;small thing&rsquo; compared to the military deliverance — YHWH&rsquo;s capacity is calibrated not by human measures of difficulty. Luke 18:27: &lsquo;what is impossible with man is possible with God.&rsquo; The prophet&rsquo;s confidence in divine capability rests on YHWH&rsquo;s track record: one who parted seas, provided manna, and now fills desert valleys with water finds military victory easy.</p>",
    "19": "<p>&lsquo;You shall attack every fortified city and every choice city, and shall fell every good tree and stop up all springs of water and ruin every good piece of land with stones.&rsquo; The destruction of agricultural infrastructure — normally forbidden in Deuteronomic law (Deut 20:19-20 prohibiting felling fruit trees during siege) — is here commanded against Moab. The exception reveals that the judgment on Moab is of a different order: this is not ordinary warfare but a covenantal execution. The total nature of the judgment anticipates the eschatological judgment described in Rev 16-18.</p>",
    "20": "<p>&lsquo;In the morning, when the offering was presented (<em>kēʿēt haggišš hamminhāh</em>), water came from the direction of Edom and the land was filled with water.&rsquo; The water arrives at the time of the morning sacrifice — the appointed hour of worship and intercession in the temple system (Exod 29:38-42; Num 28:3-8; Dan 9:21 &lsquo;at the time of the evening offering&rsquo;). The coincidence of the provision with the sacrificial hour is not accidental: the water comes within the framework of the covenant cultus, at the moment when Israel is oriented toward YHWH. The provision through the sacrifice-hour anticipates the water and blood from the side of Christ (John 19:34) — the ultimate sacrifice from which living water flows.</p>",
    "21": "<p>When the Moabites hear that the kings have come to fight, they muster everyone able to bear armor. They come to the border camp and look toward the water in the early morning — and the water looks blood-red (<em>ʾāḏōm kammayyim ʾeṯ-haḏḏām</em>). The red water is the instrument of Moab&rsquo;s undoing: they conclude that the kings have fought each other. The divine provision meant to sustain the coalition becomes, through Moab&rsquo;s misreading, the deception that leads them into the ambush. The enemy&rsquo;s error is part of the divine strategy — what YHWH provides for his people becomes the snare of those who oppose them.</p>",
    "22": "<p>The water appears blood-red in the sunlight — a natural optical effect (iron-bearing soil from Edom) given supernatural timing. Moab concludes: &lsquo;This is blood; the kings have surely fought together (<em>ḥāreḇ neḥerĕḇû hammělaḵîm</em>) and struck one another down.&rsquo; The misreading of the sign is the fundamental error of those who interpret physical reality without the prophetic word. The same blood-red water that the coalition drinks for life, Moab reads as death. The Passover blood on the doorposts (Exod 12:23) similarly divides: what is salvation for Israel is judgment for Egypt.</p>",
    "23": "<p>&lsquo;Now therefore, Moab, to the plunder!&rsquo; (<em>wĕʿattāh mwʾāḇ laššālāl</em>). The premature confidence of the enemy who misreads the divine sign is the prelude to their defeat. Overconfidence based on misinterpreted evidence is the consistent pattern of those who oppose YHWH&rsquo;s purposes — the wisdom of the cross is &lsquo;foolishness to those who are perishing&rsquo; (1 Cor 1:18) precisely because they misread what God has done.</p>",
    "24": "<p>Israel rises up and strikes the Moabites, who flee. The coalition advances and continues to strike Moab. The battle follows immediately from the prophetic word of vv16-19 — the military victory is the fulfillment of the prophetic promise, not an independent achievement. The coalition is the instrument of a divinely-shaped outcome.</p>",
    "25": "<p>They demolish the cities, fill the good fields with stones, stop up the springs, cut down the good trees, until only Kir-hareseth (the capital) is left standing. The systematic destruction of Moab&rsquo;s agricultural base is the execution of the oracle of v19. The stoning of the good fields is an act of covenantal judgment — returning the land to unproductivity as a sign of divine curse. The partial nature of the destruction (Kir-hareseth remains) sets up the final, unexpected reversal of vv26-27.</p>",
    "26": "<p>When the king of Moab sees the battle going against him, he attempts to break through to the king of Edom with 700 swordsmen — and fails. The human strategies are exhausted; the military situation is beyond recovery by human means. The desperation that follows produces the most disturbing act of the narrative.</p>",
    "27": "<p>The king of Moab takes his firstborn son who was to reign after him (<em>ʾet-bĕnô habbĕḵôr ʾăšer yimlōḵ taḥtāyw</em>) and offers him as a burnt offering on the wall (<em>wayaʿălēhû ʿōlāh ʿal-haḥōmāh</em>). &lsquo;Then great wrath came against Israel (<em>wayhî qeṣep-gāḏôl ʿal-yiśrāʾēl</em>) and they withdrew from him and returned to their land.&rsquo; The <em>qeṣep</em> (wrath) is unattributed — the grammar does not specify whether it is YHWH&rsquo;s wrath, the psychological shock on the coalition, or a perceived manifestation of Chemosh&rsquo;s power. The text&rsquo;s ambiguity is deliberate. What the passage contributes to the christological storyline is a grotesque shadow: the human king in extremis sacrifices his own firstborn son on the wall to turn back enemies. This is the inverse of the divine economy: YHWH sacrifices not his enemies&rsquo; firstborn (Exod 12:29) but his own Firstborn, freely and redemptively, to turn back the wrath that stands against those he loves. Rom 8:32: &lsquo;He who did not spare his own Son but gave him up for us all&rsquo; (<em>hos ge tou idiou huiou ouk epheisato alla hyper hēmōn pantōn paredōken auton</em>). Mesha&rsquo;s sacrifice is the desperate act of a human king to save his kingdom; the Father&rsquo;s sacrifice is the free act of divine love to save his enemies. The contrast is total.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', '2kings')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', '2kings', c)
    count = sum(len(v) for v in CHRIST.values())
    print(f'2kings mkt-christ ch 1-3: wrote {count} verses')

if __name__ == '__main__':
    main()
